"const fs = require('fs');
const path = require('path');
const readline = require('readline');

const brainDir = 'C:\\Users\\paulo\\.gemini\\antigravity\\brain';

async function restore() {
  const dirs = fs.readdirSync(brainDir);
  let bestFile = null;
  let bestLength = 0;
  let bestCode = null;

  for (const dir of dirs) {
    const transcriptPath = path.join(brainDir, dir, '.system_generated', 'logs', 'transcript.jsonl');
    if (!fs.existsSync(transcriptPath)) continue;

    console.log('Analisando:', transcriptPath);
    const fileStream = fs.createReadStream(transcriptPath);
    const rl = readline.createInterface({
      input: fileStream,
      crlfDelay: Infinity
    });

    for await (const line of rl) {
      try {
        const obj = JSON.parse(line);
        // Procuramos por write_to_file ou replace_file_content que gravem o CompanyDashboard
        if (obj.tool_calls) {
          for (const tc of obj.tool_calls) {
            if (tc.name === 'write_to_file' && tc.args && tc.args.TargetFile && tc.args.TargetFile.includes('CompanyDashboard.tsx')) {
              const code = tc.args.CodeContent;
              if (code && code.length > bestLength) {
                bestLength = code.length;
                bestCode = code;
                bestFile = { dir, name: tc.name, length: code.length };
              }
            }
          }
        }
      } catch (e) {
        // Ignore
      }
    }
  }

  if (bestCode) {
    console.log('MELHOR CORRESPONDÊNCIA ENCONTRADA:');
    console.log(JSON.stringify(bestFile, null, 2));
    fs.writeFileSync('C:\\Users\\paulo\\antigravity\\Colaborh---Conectando-Talentos\\scratch\\restored_CompanyDashboard.tsx', bestCode, 'utf8');
    console.log('restored_CompanyDashboard.tsx salvo com sucesso!');
  } else {
    console.log('Nenhum código completo encontrado nos transcripts.');
  }
}

restore();
"
